export class Controls{constructor({steps:t,onStep:e,onPlay:s}){this.steps=t.map(String),this.onStep=e,this.chipsEl=document.getElementById("step-chips"),this.playBtn=document.getElementById("play-btn"),this.captionEl=document.getElementById("caption");for(const t of this.steps){const s=document.createElement("button");s.textContent="inf"===t?"\u221e":t,s.dataset.step=t,s.addEventListener("click",()=>e(t)),this.chipsEl.appendChild(s)}this.playBtn.addEventListener("click",s)}setActiveStep(t){this.chipsEl.querySelectorAll("button").forEach(e=>e.classList.toggle("active",e.dataset.step===String(t)))}setPlaying(t){this.playBtn.textContent=t?"\u23f8 pause":"\u25b6 play"}setCaption(t){this.captionEl.textContent=t}}